import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { FiMail, FiLock, FiEye, FiEyeOff, FiBookOpen } from 'react-icons/fi';
import toast from 'react-hot-toast';
import { login as loginApi } from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import './AuthPages.css';

export default function LoginPage() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ email: '', motDePasse: '' });
  const [showPwd, setShowPwd] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await loginApi(form);
      login(res.data.token, res.data.user);
      toast.success(`Bienvenue, ${res.data.user.prenom}!`);
      navigate('/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Erreur de connexion');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-card">

        {/* Left blue panel */}
        <div className="auth-bg">
          <div className="auth-bg-inner-circle" />
          <div className="auth-brand">
            <div className="auth-logo"><FiBookOpen /></div>
            <h1>Bienvenue</h1>
            <p>Plateforme de gestion des projets de fin d'études</p>
          </div>
        </div>

        {/* Right white panel */}
        <div className="auth-form-side">
          <div className="auth-form-container">
            <div className="auth-header">
              <h2>Sign in</h2>
              <p>Entrez vos identifiants pour continuer</p>
            </div>

            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <div className="input-wrapper">
                  <FiMail className="input-icon" />
                  <input
                    type="email"
                    className="form-input with-icon"
                    placeholder="Adresse email"
                    value={form.email}
                    onChange={e => setForm({ ...form, email: e.target.value })}
                    required
                  />
                </div>
              </div>

              <div className="form-group">
                <div className="input-wrapper">
                  <FiLock className="input-icon" />
                  <input
                    type={showPwd ? 'text' : 'password'}
                    className="form-input with-icon"
                    placeholder="Mot de passe"
                    value={form.motDePasse}
                    onChange={e => setForm({ ...form, motDePasse: e.target.value })}
                    required
                  />
                  <button type="button" className="pwd-toggle" onClick={() => setShowPwd(!showPwd)}>
                    {showPwd ? <FiEyeOff /> : <FiEye />}
                  </button>
                </div>
              </div>

              <div className="auth-forgot">
                <Link to="/forgot-password">Mot de passe oublié?</Link>
              </div>

              <button type="submit" className="auth-submit" disabled={loading}>
                {loading ? <><span className="btn-spinner"></span>Connexion...</> : 'Se connecter'}
              </button>
            </form>

            <div className="auth-footer">
              <p>Pas encore de compte? <Link to="/register">S'inscrire</Link></p>
            </div>

            {false && (
              <div className="demo-accounts">
                <p className="demo-title">🛠️ Comptes de démonstration</p>
                <div className="demo-btns">
                  {[
                    { label: 'Admin', email: 'admin@pfe.com', pwd: 'Admin@123' },
                    { label: 'Encadrant', email: 'supervisor@pfe.com', pwd: 'Super@123' },
                    { label: 'Étudiant', email: 'student@pfe.com', pwd: 'Student@123' },
                  ].map(acc => (
                    <button key={acc.label} className="demo-btn"
                      onClick={() => setForm({ email: acc.email, motDePasse: acc.pwd })}>
                      {acc.label}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>

      </div>
    </div>
  );
}
